import "./Footer.css";
import { useState } from "react";

/**
 * Footer
 * Minimal brand strip with Indian & Tamil Nadu wedding photos.
 */
export default function Footer() {
  const year = new Date().getFullYear();
  const [loadedImages, setLoadedImages] = useState({});

  const footerPhotos = [
    {
      src: "/images/img1.jpg",
      alt: "Indian Wedding Temple Ceremony",
    },
    {
      src: "/images/img2.jpg",
      alt: "Bridal Portrait Wedding",
    },
    {
      src: "/images/img3.jpg",
      alt: "Traditional Wedding Couple",
    },
    {
      src: "/images/img4.jpg",
      alt: "South Indian Bride",
    },
    {
      src: "/images/img5.jpg",
      alt: "Engagement Couple Portrait",
    },
    {
      src: "/images/img6.jpg",
      alt: "Wedding Celebration Couple",
    },
  ];

  const handleImageLoad = (idx) => {
    setLoadedImages(prev => ({ ...prev, [idx]: true }));
  };

  const handleImageError = (e) => {
    e.target.style.opacity = '0';
  };

  return (
    <footer className="footer">
      <div className="footer__content">
        <div className="footer__text">
          <span className="footer__brand">
            Ayyan Studio <em>Classics</em>
          </span>
          <span className="footer__info">
            © {year} · South Indian Wedding Specialists
          </span>
        </div>

        <div className="footer__gallery">
          {footerPhotos.map((photo, idx) => (
            <div key={idx} className="footer__gallery-item">
              <img 
                src={photo.src} 
                alt={photo.alt} 
                loading="lazy"
                decoding="async"
                data-loaded={loadedImages[idx] ? "true" : "false"}
                onLoad={() => handleImageLoad(idx)}
                onError={handleImageError}
              />
            </div>
          ))}
        </div>
      </div>
    </footer>
  );
}
